options.css:
.rsc-message-browser { height: 100%; min-height: 0; display: flex; flex-direction: column; font-family: Inter, Arial, sans-serif; color: inherit; --rsc-border: color-mix(in srgb, currentColor 18%, transparent); --rsc-soft: color-mix(in srgb, currentColor 7%, transparent); --rsc-softer: color-mix(in srgb, currentColor 4%, transparent); --rsc-muted: color-mix(in srgb, currentColor 62%, transparent); --rsc-blue: #5794f2; }
.rsc-message-toolbar { display: flex; flex-wrap: wrap; gap: 8px; align-items: center; margin-bottom: 10px; }
.rsc-message-nav { display: inline-flex; align-items: center; gap: 4px; }
.rsc-message-nav button { min-width: 32px; padding: 0 8px; font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; font-size: 13px; }
.rsc-message-search { display: inline-flex; align-items: center; gap: 6px; flex-wrap: wrap; }
.rsc-message-search input { height: 32px; min-width: 260px; border-radius: 6px; border: 1px solid var(--rsc-border); background: var(--rsc-softer); color: inherit; padding: 0 10px; font-size: 12px; font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; outline: none; }
.rsc-message-search input:focus { border-color: var(--rsc-blue); box-shadow: 0 0 0 1px color-mix(in srgb, var(--rsc-blue) 42%, transparent); }
.rsc-message-toolbar label { display: inline-flex; align-items: center; gap: 6px; font-size: 12px; color: var(--rsc-muted); }
.rsc-message-toolbar select, .rsc-message-toolbar button { height: 32px; border-radius: 6px; border: 1px solid var(--rsc-border); background: var(--rsc-soft); color: inherit; padding: 0 10px; font-size: 12px; }
.rsc-message-toolbar button { cursor: pointer; background: var(--rsc-blue); border-color: var(--rsc-blue); color: #fff; font-weight: 650; }
.rsc-message-toolbar button.secondary { background: var(--rsc-soft); border-color: var(--rsc-border); color: inherit; }
.rsc-message-toolbar button.secondary:hover { border-color: var(--rsc-blue); }
.rsc-message-toolbar button:disabled { cursor: not-allowed; opacity: 0.45; }
.rsc-message-context { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 10px; color: var(--rsc-muted); font-size: 12px; }
.rsc-message-context span { padding: 4px 8px; border: 1px solid var(--rsc-border); border-radius: 999px; background: var(--rsc-softer); }
.rsc-message-context strong { color: inherit; }
.rsc-message-status { margin: 6px 0 10px; font-size: 12px; color: var(--rsc-muted); min-height: 18px; }
.rsc-message-status.error { color: #f2495c; }
.rsc-message-table-wrap { flex: 1 1 auto; min-height: 0; overflow: auto; border: 1px solid var(--rsc-border); border-radius: 8px; background: var(--rsc-softer); }
.rsc-message-table { width: 100%; border-collapse: collapse; table-layout: fixed; font-size: 12px; }
.rsc-message-table th { position: sticky; top: 0; background: color-mix(in srgb, currentColor 8%, transparent); color: inherit; text-align: left; border-bottom: 1px solid var(--rsc-border); padding: 8px 9px; font-weight: 700; backdrop-filter: blur(6px); }
.rsc-message-table td { vertical-align: top; border-top: 1px solid color-mix(in srgb, currentColor 9%, transparent); padding: 8px 9px; }
.rsc-message-table tbody tr:hover { background: var(--rsc-soft); }
.rsc-message-offset { width: 170px; white-space: nowrap; font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; }
.rsc-message-stream { width: 260px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; }
.rsc-message-payload, .rsc-message-fields { white-space: pre-wrap; word-break: break-word; font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; max-height: none; overflow: visible; }
.rsc-message-empty { padding: 18px; color: var(--rsc-muted); text-align: center; }
.rsc-message-shards { display: flex; flex-wrap: wrap; gap: 6px; margin: 0 0 10px; }
.rsc-message-shard-chip { height: 28px; min-width: 36px; border-radius: 999px; border: 1px solid var(--rsc-border); background: var(--rsc-soft); color: inherit; padding: 0 9px; font-size: 12px; cursor: pointer; }
.rsc-message-shard-chip:hover { border-color: var(--rsc-blue); }
.rsc-message-shard-chip.active { background: var(--rsc-blue); border-color: var(--rsc-blue); color: #fff; font-weight: 700; }
.rsc-message-note { flex-basis: 100%; font-size: 11px; color: var(--rsc-muted); margin-top: 2px; }

options.onInit:
const root = htmlNode.querySelector('.rsc-message-browser');
if (!root || root.dataset.bound === 'true') {
  return;
}
root.dataset.bound = 'true';

function variable(name) {
  const token = '$' + name;
  if (htmlGraphics.props && typeof htmlGraphics.props.replaceVariables === 'function') {
    return htmlGraphics.props.replaceVariables(token);
  }
  if (htmlGraphics.getTemplateSrv) {
    return htmlGraphics.getTemplateSrv().replace(token);
  }
  return token;
}

const proxyPath = '/api/datasources/proxy/uid/${DS_RSC_COORDINATOR_API}/coord/v1/monitoring/grafana/messages';
const shardOptionsProxyPath = '/api/datasources/proxy/uid/${DS_RSC_COORDINATOR_API}/coord/v1/monitoring/grafana/options/shards';
const state = {
  cursors: [''],
  page: 0,
  nextCursor: '',
  loading: false,
  totalMessages: '-',
  selection: null,
  selectedShardOverride: null,
  shardOptions: [],
  shardOptionsSignature: '',
  recordId: '',
};

function byRole(role) { return root.querySelector('[data-role="' + role + '"]'); }
function action(name) { return root.querySelector('[data-action="' + name + '"]'); }
function text(value) { return value == null || value === '' ? '-' : String(value); }
function normalizeShardValue(value) {
  const raw = String(value == null ? '' : value).trim();
  if (raw === '' || raw === '.*' || raw === '$__all' || raw.toLowerCase() === 'all') {
    return 'all';
  }
  return raw.replace(/^:/, '');
}
function rawVariableSelection() {
  return {
    streamPrefix: variable('streamPrefix'),
    consumerGroup: variable('consumerGroup'),
    shardIndex: normalizeShardValue(variable('shardIndex')),
  };
}
function currentSelection() {
  const raw = rawVariableSelection();
  const shardIndex = state.selectedShardOverride || raw.shardIndex;
  return {
    streamPrefix: raw.streamPrefix,
    consumerGroup: raw.consumerGroup,
    shardIndex: shardIndex,
    signature: [raw.streamPrefix, raw.consumerGroup, shardIndex].join('\u0000'),
    rawSignature: [raw.streamPrefix, raw.consumerGroup, raw.shardIndex].join('\u0000'),
  };
}
function syncSelection(resetOnChange) {
  const previous = state.selection;
  const next = currentSelection();
  const rawChanged = previous && previous.rawSignature !== next.rawSignature;
  if (rawChanged) {
    state.selectedShardOverride = null;
  }
  const effective = rawChanged ? currentSelection() : next;
  const changed = !previous || previous.signature !== effective.signature;
  state.selection = effective;
  if (changed && resetOnChange !== false) {
    resetPaging();
    state.totalMessages = '-';
  }
  return changed || rawChanged;
}
function selection() {
  if (!state.selection) syncSelection(false);
  return state.selection;
}
function isAllShardSelected() { return selection().shardIndex === 'all'; }
function escapeHtml(value) {
  return text(value).replace(/[&<>"']/g, function (ch) {
    return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[ch];
  });
}
function setStatus(message, isError) {
  const el = byRole('status');
  el.textContent = message || '';
  el.classList.toggle('error', !!isError);
}
function currentCursor() {
  return state.cursors[state.page] || '';
}
function tailCursor(distanceFromLast) {
  const distance = Math.max(0, Number(distanceFromLast) || 0);
  return '__rsc_tail__:' + distance;
}
function tailCursorDistance(cursor) {
  const value = String(cursor == null ? '' : cursor).trim();
  if (value === '__rsc_last__') return 0;
  if (!value.startsWith('__rsc_tail__:')) return null;
  const parsed = Number(value.substring('__rsc_tail__:'.length));
  return Number.isFinite(parsed) && parsed >= 0 ? Math.floor(parsed) : null;
}
function isTailCursor(cursor) {
  return tailCursorDistance(cursor) !== null;
}
function canMovePrev() {
  return state.page > 0 && (typeof state.cursors[state.page - 1] !== 'undefined' || isTailCursor(currentCursor()));
}
function pageCount(totalMessages, limit) {
  const total = Number(totalMessages);
  const size = Number(limit || byRole('limit').value || '25');
  if (!Number.isFinite(total) || total < 0 || !Number.isFinite(size) || size <= 0) return null;
  return Math.max(1, Math.ceil(total / size));
}
function lastPageIndex(totalMessages, limit) {
  const count = pageCount(totalMessages, limit);
  return count == null ? 0 : Math.max(0, count - 1);
}
function setLoading(loading) {
  state.loading = loading;
  action('refresh').disabled = loading;
  action('first').disabled = loading || !!state.recordId || state.page === 0;
  action('prev').disabled = loading || !!state.recordId || !canMovePrev();
  action('next').disabled = loading || !!state.recordId || !state.nextCursor;
  const totalNumber = Number(state.totalMessages);
  const knownTotal = Number.isFinite(totalNumber) && totalNumber > 0;
  const atKnownLast = knownTotal && state.page >= lastPageIndex(totalNumber, byRole('limit').value);
  action('last').disabled = loading || !!state.recordId || !canQuery() || !knownTotal || atKnownLast;
}
function updateContext() {
  const current = selection();
  byRole('stream-prefix').textContent = text(current.streamPrefix);
  byRole('consumer-group').textContent = text(current.consumerGroup);
  byRole('shard-index').textContent = state.recordId ? 'All (record id search)' : (isAllShardSelected() ? 'All' : ':' + text(current.shardIndex));
  const pages = pageCount(state.totalMessages, byRole('limit').value);
  const currentPage = pages == null ? state.page + 1 : Math.min(state.page + 1, pages);
  byRole('page-number').textContent = state.recordId ? 'Search' : (String(currentPage) + ' / ' + (pages == null ? '-' : String(pages)));
  const totalEl = byRole('total-messages');
  if (totalEl) totalEl.textContent = text(state.totalMessages);
  renderShardChips();
}
function resetPaging() {
  state.cursors = [''];
  state.page = 0;
  state.nextCursor = '';
}
function renderShardChips() {
  const container = byRole('shard-chips');
  if (!container) return;
  const current = selection();
  const options = [{ text: 'All', value: 'all' }].concat(state.shardOptions);
  container.innerHTML = options.map(function (option) {
    const value = normalizeShardValue(option.value);
    const label = value === 'all' ? 'All' : ':' + value;
    const active = value === current.shardIndex ? ' active' : '';
    return '<button type="button" class="rsc-message-shard-chip' + active + '" data-shard="' + escapeHtml(value) + '">' + escapeHtml(label) + '</button>';
  }).join('') + '<div class="rsc-message-note">All reads a candidate range from every shard, merge-sorts by Redis Stream ID, and returns only the selected page size. Select one shard for cheaper point inspection.</div>';
  Array.prototype.forEach.call(container.querySelectorAll('[data-shard]'), function (button) {
    button.addEventListener('click', function () {
      const nextShard = normalizeShardValue(button.getAttribute('data-shard'));
      if (nextShard === selection().shardIndex) return;
      state.selectedShardOverride = nextShard;
      state.recordId = '';
      byRole('record-id').value = '';
      resetPaging();
      state.totalMessages = '-';
      syncSelection(false);
      updateContext();
      loadPage();
    });
  });
}
function renderRows(rows) {
  const tbody = byRole('rows');
  const empty = byRole('empty');
  tbody.innerHTML = '';
  if (!rows || rows.length === 0) {
    empty.style.display = 'block';
    return;
  }
  empty.style.display = 'none';
  rows.forEach(function (row) {
    const tr = document.createElement('tr');
    tr.innerHTML = '<td class="rsc-message-offset" title="' + escapeHtml(row.streamKey) + '">' + escapeHtml(row.shardLabel || (':' + row.shardIndex)) + '</td>' +
      '<td class="rsc-message-offset">' + escapeHtml(row.recordId) + '</td>' +
      '<td><div class="rsc-message-payload">' + escapeHtml(row.payload) + '</div></td>' +
      '<td><div class="rsc-message-fields">' + escapeHtml(row.fieldsJson) + '</div></td>';
    tbody.appendChild(tr);
  });
}
function canQuery() {
  const current = selection();
  return current.streamPrefix && current.consumerGroup && current.shardIndex &&
    current.streamPrefix.indexOf('$') === -1 &&
    current.consumerGroup.indexOf('$') === -1 &&
    (isAllShardSelected() || current.shardIndex.indexOf('$') === -1);
}
function buildUrl() {
  const current = selection();
  const params = new URLSearchParams();
  params.set('streamPrefix', current.streamPrefix);
  params.set('consumerGroup', current.consumerGroup);
  params.set('shardIndex', current.shardIndex);
  params.set('direction', byRole('direction').value || 'BACKWARD');
  params.set('limit', byRole('limit').value || '25');
  if (state.recordId) {
    params.set('recordId', state.recordId);
  }
  if (!state.recordId && state.cursors[state.page]) {
    params.set('cursor', state.cursors[state.page]);
  }
  return proxyPath + '?' + params.toString();
}
async function loadShardOptions() {
  const current = selection();
  const signature = [current.streamPrefix, current.consumerGroup].join('\u0000');
  if (!current.streamPrefix || !current.consumerGroup || signature === state.shardOptionsSignature) {
    return;
  }
  state.shardOptionsSignature = signature;
  const params = new URLSearchParams();
  params.set('streamPrefix', current.streamPrefix);
  params.set('consumerGroup', current.consumerGroup);
  try {
    const response = await fetch(shardOptionsProxyPath + '?' + params.toString(), { credentials: 'same-origin', headers: { 'Accept': 'application/json' } });
    if (!response.ok) throw new Error('HTTP ' + response.status);
    const parsed = await response.json();
    state.shardOptions = (Array.isArray(parsed) ? parsed : []).map(function (row) {
      return { text: row.__text || row.text || row.__value || row.value, value: row.__value || row.value || row.__text || row.text };
    });
    renderShardChips();
  } catch (error) {
    state.shardOptions = [];
    renderShardChips();
  }
}
async function loadPage() {
  if (state.loading) return;
  syncSelection(true);
  updateContext();
  loadShardOptions();
  if (!canQuery()) {
    renderRows([]);
    setStatus('Select a stream, consumer group, and shard before reading messages.', true);
    setLoading(false);
    return;
  }
  setLoading(true);
  setStatus('Loading messages...');
  try {
    const response = await fetch(buildUrl(), { credentials: 'same-origin', headers: { 'Accept': 'application/json' } });
    if (!response.ok) {
      throw new Error('HTTP ' + response.status + ' ' + response.statusText);
    }
    const parsed = await response.json();
    const rows = Array.isArray(parsed) ? parsed : [];
    const appliedLimit = rows.length > 0 ? Number(rows[0].pageLimit || byRole('limit').value || '25') : Number(byRole('limit').value || '25');
    const reportedNextCursor = rows.length > 0 ? (rows[rows.length - 1].pageNextCursor || '') : '';
    const totalMessages = rows.length > 0 ? Number(rows[0].pageTotalMessages || 0) : 0;
    const requestedTailDistance = !state.recordId ? tailCursorDistance(currentCursor()) : null;
    const requestedTailPage = requestedTailDistance !== null;
    const loadedThroughPage = state.page * appliedLimit + rows.length;
    const fallbackNextCursor = !requestedTailPage && !state.recordId && rows.length === appliedLimit && totalMessages > loadedThroughPage
      ? rows[rows.length - 1].recordId
      : '';
    state.totalMessages = totalMessages;
    if (requestedTailPage) {
      const lastIndex = lastPageIndex(totalMessages, appliedLimit);
      const targetPage = Math.max(0, lastIndex - requestedTailDistance);
      const actualDistance = lastIndex - targetPage;
      state.page = targetPage;
      state.cursors[state.page] = tailCursor(actualDistance);
      state.nextCursor = reportedNextCursor || (actualDistance > 0 ? tailCursor(actualDistance - 1) : '');
    } else {
      state.nextCursor = reportedNextCursor || fallbackNextCursor;
    }
    renderRows(rows);
    updateContext();
    const scope = state.recordId ? 'record id ' + state.recordId + ' across all shards' : (isAllShardSelected() ? 'all shards' : ':' + selection().shardIndex);
    if (state.recordId) {
      setStatus(rows.length + ' matching message(s) loaded from coordinator API for ' + scope + ' / total ' + state.totalMessages + '.');
    } else {
      setStatus(rows.length + '/' + appliedLimit + ' message(s) loaded from coordinator API for ' + scope + ' / total ' + state.totalMessages + (state.nextCursor ? '.' : ' (end of selection).'));
    }
  } catch (error) {
    state.nextCursor = '';
    renderRows([]);
    updateContext();
    setStatus('Failed to load messages: ' + error.message, true);
  } finally {
    setLoading(false);
  }
}

byRole('record-id').addEventListener('keydown', function (event) {
  if (event.key === 'Enter') {
    state.recordId = byRole('record-id').value.trim();
    state.selectedShardOverride = state.recordId ? 'all' : state.selectedShardOverride;
    resetPaging();
    loadPage();
  }
});
action('search-record').addEventListener('click', function () {
  state.recordId = byRole('record-id').value.trim();
  state.selectedShardOverride = state.recordId ? 'all' : state.selectedShardOverride;
  resetPaging();
  loadPage();
});
action('clear-search').addEventListener('click', function () {
  state.recordId = '';
  byRole('record-id').value = '';
  resetPaging();
  loadPage();
});
byRole('limit').addEventListener('change', function () { resetPaging(); loadPage(); });
byRole('direction').addEventListener('change', function () { resetPaging(); loadPage(); });
action('refresh').addEventListener('click', function () { resetPaging(); loadPage(); });
action('first').addEventListener('click', function () {
  resetPaging();
  loadPage();
});
action('prev').addEventListener('click', function () {
  if (canMovePrev()) {
    const previousPage = state.page - 1;
    const distance = tailCursorDistance(currentCursor());
    if (distance !== null && typeof state.cursors[previousPage] === 'undefined') {
      state.page = previousPage;
      state.cursors[state.page] = tailCursor(distance + 1);
    } else {
      state.page = previousPage;
      state.cursors = state.cursors.slice(0, state.page + 1);
    }
    state.nextCursor = '';
    loadPage();
  }
});
action('next').addEventListener('click', function () {
  if (state.nextCursor) {
    state.page += 1;
    state.cursors[state.page] = state.nextCursor;
    state.nextCursor = '';
    loadPage();
  }
});
action('last').addEventListener('click', function () {
  const targetPage = lastPageIndex(state.totalMessages, byRole('limit').value);
  state.cursors = [];
  state.page = targetPage;
  state.cursors[state.page] = tailCursor(0);
  state.nextCursor = '';
  loadPage();
});

syncSelection(false);
updateContext();
setLoading(false);
loadShardOptions();
loadPage();

const variableWatch = window.setInterval(function () {
  if (!root.isConnected) {
    window.clearInterval(variableWatch);
    return;
  }
  const changed = syncSelection(true);
  updateContext();
  if (changed) {
    loadShardOptions();
    loadPage();
  }
}, 1000);
